INSERT INTO posts (id, user_id, space_id, title, body, created_at, is_seeded) VALUES
('4593e822-385a-510c-8c18-68bad2fe2719', NULL, 'commons', 'Why do I feel so alone even when surrounded by people?', 'I went to a party last night with like 50 people. Laughed, danced, had drinks. Felt completely alone the whole time. Does anyone else get this? Like my body is there but Im somewhere else entirely.', NOW() - INTERVAL '15 days', true),
('bc302285-43d0-5acd-bda2-240186ff253b', NULL, 'commons', 'My therapist asked me when I last felt safe', 'I literally had to think for like 5 minutes. Safe. Not happy or successful or connected, just... safe. Thats a weird thing to have to think about that long. Anyone else struggle with this?', NOW() - INTERVAL '13 days', true),
('eeb3078d-9307-5867-9474-e88d5deb41ea', NULL, 'commons', 'I made a mistake and its eating me alive', 'Said something hurtful to someone I care about. They said its fine but I dont believe them. I keep replaying it. When does this get easier? Does it ever?', NOW() - INTERVAL '10 days', true),
('493f827d-b631-53ec-8233-a85d1f020cb5', NULL, 'commons', 'Small win: I asked for help today', 'I actually texted a friend and said I was struggling instead of just suffering in silence. It felt weird but good? Like I didnt have to have it all figured out for once. This shouldnt feel this revolutionary but it does.', NOW() - INTERVAL '9 days', true),
('f3c02198-e14a-5568-91ec-616b44b0a5de', NULL, 'commons', 'Why do I still care what my parents think?', 'Theyre not around. Theyre dead. Yet I still hear their judgment in my head constantly. Im 40 years old. This shouldnt still be happening. Is this normal?', NOW() - INTERVAL '8 days', true),
('0ab47ba1-9ef8-5bb9-b7f2-4c7e44695d60', NULL, 'dating-desire', 'I dont know how to be sexual without feeling shame', 'Even with someone I trust, theres this voice telling me its wrong or dirty. I know intellectually thats not true but my body doesnt believe it. How do you untrain yourself?', NOW() - INTERVAL '12 days', true),
('3e65224b-a2f9-5c72-9bcb-de94ec6934a5', NULL, 'dating-desire', 'Dating apps make me feel like shit about myself', 'Spent two hours swiping. Matched with three people. Nobodys responding. I know this is shallow nonsense but why does my self-worth tank every time I use these apps?', NOW() - INTERVAL '11 days', true),
('bc825afc-3441-558c-84be-db5b25636004', NULL, 'dating-desire', 'Im tired of pretending to be fine', 'On dates I act like I have my shit together. Career, apartment, gym routine. But inside Im a mess. When do I get to actually be honest with someone?', NOW() - INTERVAL '7 days', true),
('6f766808-87b5-56da-8a5d-0e725b8a04db', NULL, 'dating-desire', 'Why does vulnerability feel like weakness?', 'I want to tell someone I like them but Im terrified. Not of rejection exactly. More of... being seen. Of them knowing the real version of me and leaving because of it.', NOW() - INTERVAL '6 days', true),
('7f94e4ec-b383-5a3f-99ca-e9f412e74430', NULL, 'dating-desire', 'Small victory: I said no to someone', 'Usually I say yes to everything because Im afraid nobody else will want me. But this time I actually said no. Felt guilty immediately but also a tiny bit proud? Is that growth?', NOW() - INTERVAL '5 days', true),
('415a04e0-408c-5ac4-b4cc-7f9296ef5357', NULL, 'touch-affection', 'Im touch-starved and its affecting my mental health', 'Havent been hugged in months. This sounds pathetic but I actually miss just being held. Not sexually, just... held. Does anyone else feel this?', NOW() - INTERVAL '14 days', true),
('5c03ed36-b993-52b0-b201-3b059cb723f1', NULL, 'touch-affection', 'Why is asking for physical affection so hard?', 'I want my friends to hug me more. Want to be more physically affectionate in general. But I dont know how without it being weird or seeming like I want something sexual.', NOW() - INTERVAL '11 days', true),
('e680c3bf-9afa-5152-a611-f48da7c0733e', NULL, 'touch-affection', 'My partner doesnt like to cuddle and its killing me', 'He says its too hot or he cant sleep. I get it but it makes me feel rejected. And then I feel needy for being bothered by it. Stuck in a loop here.', NOW() - INTERVAL '9 days', true),
('c3e1d7b1-4adf-5966-b21a-7431f1c6fcb1', NULL, 'touch-affection', 'Discovered I need touch to feel loved', 'Been working through some stuff and realized physical affection is my primary love language. Feels stupid to just be figuring this out at 28 but better late than never I guess?', NOW() - INTERVAL '8 days', true),
('de28d666-fdb0-5850-a2ab-ad4acb64a1b9', NULL, 'embodiment', 'I hate my body and I hate that I hate it', 'Spent 30 years as a thin guy. Got older, gained weight. Now I feel invisible. Which is ridiculous because Im literally more visible at this weight. My brain is broken.', NOW() - INTERVAL '12 days', true),
('989d6ade-5623-512b-aafc-788eed393dad', NULL, 'embodiment', 'Why is self-acceptance so hard?', 'Logically I know my body is fine. Functionally it works. But every mirror is a fight. Every photo is a disappointment. When does this get better?', NOW() - INTERVAL '10 days', true),
('b13335ee-69d6-5f42-91ca-9b93051ab6c4', NULL, 'embodiment', 'Started working out for myself, not for others', 'First time Ive exercised because it feels good, not because Im trying to be attractive. Wild difference. Anyone else find this?', NOW() - INTERVAL '8 days', true),
('2fe2574c-1da6-5113-8200-d1a5651d8bb3', NULL, 'embodiment', 'My body keeps score', 'I know about trauma living in the body. But actually feeling it? The tension, the numbness, the way I brace myself? Thats different. How do I actually work with this?', NOW() - INTERVAL '6 days', true),
('ff20135a-f7e2-5866-a8c8-82215443da49', NULL, 'couples', 'We had our first real fight and I thought it was over', 'We didnt just calmly discuss it. We yelled. Cried. Said things we didnt mean. Thought that meant we were doomed. But we worked through it. Maybe thats normal?', NOW() - INTERVAL '13 days', true),
('05d7328e-5b63-5e52-bbcb-6fb0d96ea181', NULL, 'couples', 'My partner is my best friend but also my biggest trigger', 'He knows exactly how to hurt me. Not because hes mean but because he knows me. Some days this feels like a problem. Most days I think its actually beautiful?', NOW() - INTERVAL '11 days', true),
('02507f50-b613-5269-a783-6393890702d1', NULL, 'couples', 'Weve been together for 5 years and the novelty is gone', 'Is that okay? Do relationships have to stay exciting? Or can they just be... steady? Comfortable? I think I actually like it but something in me says it should still feel like the beginning.', NOW() - INTERVAL '9 days', true),
('96743880-bfa9-5c7c-9752-9c4068361cbb', NULL, 'couples', 'After my breakup, Im finally breathing', 'Was with him for 7 years. Spent the last 2 knowing it wasnt working but staying anyway. Its been a month. Some days I miss him. Most days I just feel relief.', NOW() - INTERVAL '7 days', true),
('9926dcc3-9c55-5d51-bef6-71806482cea6', NULL, 'spirituality-sexuality', 'Reconciling my faith with my sexuality', 'Grew up being told they were incompatible. Still working through the shame even though I intellectually know its bullshit. Anyone else carrying religious trauma?', NOW() - INTERVAL '12 days', true),
('0ee4e9e4-97d8-5087-ac2a-03214e69d0f0', NULL, 'spirituality-sexuality', 'Sex used to be dirty, now its becoming sacred', 'That shift is slow and weird. Some days I can access it, other days the old programming kicks in. Patience with myself is harder than I expected.', NOW() - INTERVAL '10 days', true),
('0bb1cb5b-5c9c-5d02-ac03-b7704bbd0437', NULL, 'spirituality-sexuality', 'Im learning that my sexuality is a spiritual practice', 'Not trying to be woo about it but presence, consent, vulnerability... thats all spiritual work. Blew my mind.', NOW() - INTERVAL '8 days', true),
('643fc66e-d909-5a9b-b482-ebf21020ebd8', NULL, 'masculinity-sex-sexuality', 'What does masculinity even mean?', 'Spent my whole life proving I was man enough. Now Im wondering what I was actually trying to prove and to who.', NOW() - INTERVAL '11 days', true),
('8ea1f522-5ffd-5043-8200-f2be0fc8dbb4', NULL, 'masculinity-sex-sexuality', 'I cried and nobody died', 'Had a breakdown at the gym. Felt humiliated. Then realized: nobody actually cared. I was just... human. Revolutionary.', NOW() - INTERVAL '9 days', true),
('ff72492f-5224-507c-a61d-d4ca3cf84522', NULL, 'masculinity-sex-sexuality', 'Softness is not weakness', 'Learning this at 26. Better late than never. Trying to redefine what I think masculinity is.', NOW() - INTERVAL '7 days', true),
('cf0b7b86-9408-5f3a-8f25-08fb1def7455', NULL, 'sacred-sexuality', 'My body is holy and I dont know what to do with that', 'Conceptually I get it. Practically? Still feels heretical to think of my body as sacred instead of shameful.', NOW() - INTERVAL '12 days', true),
('b4105398-748f-567c-aec9-dfa2df70fce7', NULL, 'sacred-sexuality', 'Slowing down during sex changed everything', 'Used to just rush through. Started actually paying attention to sensation and presence. Its a completely different experience.', NOW() - INTERVAL '10 days', true),
('d663a5cf-4ecb-5ee7-88cc-188288b84af7', NULL, 'intimacy-patterns', 'I run when things get real', 'Dont know how to break this pattern. The second someone gets close, I sabotage or ghost. Recognizing it is the first step but how do I actually change?', NOW() - INTERVAL '11 days', true),
('b6d2d9e1-e6c6-5342-aa56-eb4e48390663', NULL, 'intimacy-patterns', 'Learned my avoidance from watching my parents', 'Never saw them fight, never saw them really connect either. Just separate, polite, distant. Realized Im doing the same thing. How do I write a different story?', NOW() - INTERVAL '9 days', true),
('697a75ed-d32a-5901-b1fe-d9f36d37c570', NULL, 'intimacy-patterns', 'Anxiety spikes right when things feel good', 'Its like my nervous system doesnt trust happiness. Starts looking for things to worry about. Is this fixable?', NOW() - INTERVAL '7 days', true),
('09bfd7d6-bd0b-5c24-98ca-e07d4c9d6027', NULL, 'start-here', 'Hi, Im terrified to be here', 'Never done anything like this before. Part of me is screaming to leave. But Im so tired of keeping everything inside. So here I am.', NOW() - INTERVAL '10 days', true),
('f42d0f22-bd50-51c9-b475-bc5c483bae05', NULL, 'start-here', 'Coming out was supposed to fix things', 'It didnt. Im still depressed, still struggling, still alone sometimes. Everyone acts like coming out solves everything but it just solved one thing.', NOW() - INTERVAL '8 days', true),
('704caff8-3eeb-5ca3-8101-cbb39baaa8d4', NULL, 'start-here', 'I dont have friends who get this', 'All my friends are either deeply closeted or aggressively party guys. Neither talks about real shit. Hoping this is different?', NOW() - INTERVAL '6 days', true),
('7af99368-38b0-5088-80e1-d89ff3677fe3', NULL, 'start-here', 'Nervous about judgment here', 'Ive made mistakes. Said dumb things. Hurt people. Trying to be better but scared to admit all of it. Is this place safe for that?', NOW() - INTERVAL '5 days', true),
('c0615e0f-11a5-5679-93fa-7b4436ba0455', NULL, 'start-here', 'Just checking in', 'New to this. Not even sure what Im looking for. Connection maybe? Understanding? Just... less loneliness?', NOW() - INTERVAL '4 days', true);
INSERT INTO comments (id, user_id, post_id, body, created_at, is_seeded) VALUES
('0b3c9b46-5a41-5b1e-9ed3-693c68d39a23', NULL, '4593e822-385a-510c-8c18-68bad2fe2719', 'I get this. I think its called dissociation? My therapist says I leave my body when things feel unsafe even if nothing dangerous is actually happening.', NOW() - INTERVAL '15 days', true),
('bee2fb2c-daf0-521a-ad9c-ce7a0c131fb1', NULL, '4593e822-385a-510c-8c18-68bad2fe2719', 'Youre not alone in feeling alone. That sounds contradictory but its true. A lot of us are dealing with this.', NOW() - INTERVAL '15 days', true),
('3cfc2a21-414c-5424-8dc3-8d5d13e8e709', NULL, 'bc302285-43d0-5acd-bda2-240186ff253b', 'This hit me hard. I realized Ive only felt safe twice in my adult life. Both times with the same person. Makes sense why Im holding on so tight.', NOW() - INTERVAL '15 days', true),
('d18ab27d-0afd-5859-a14d-829ad264896c', NULL, 'bc302285-43d0-5acd-bda2-240186ff253b', 'Safety is underrated. We talk about love and sex and connection but safety is foundational. Good for you for even asking the question.', NOW() - INTERVAL '14 days', true),
('6f60b960-5241-5c2c-a71d-bfdb0d929d43', NULL, 'eeb3078d-9307-5867-9474-e88d5deb41ea', 'The guilt doesnt go away quickly but it does change. At some point youll have made amends enough times that you stop catastrophizing every mistake.', NOW() - INTERVAL '14 days', true),
('3613c20e-e9ee-51db-a0ae-546886b11853', NULL, 'eeb3078d-9307-5867-9474-e88d5deb41ea', 'I spiraled over something similar for weeks. What helped was actually telling the person I was spiraling. Gave them a chance to reassure me instead of leaving me in my head.', NOW() - INTERVAL '14 days', true),
('70d69afa-be6c-5ef8-972e-ee86c72358d7', NULL, '493f827d-b631-53ec-8233-a85d1f020cb5', 'This is huge. Asking for help is literally the hardest thing and you did it. Thats not revolutionary, thats courageous.', NOW() - INTERVAL '14 days', true),
('38909e01-f755-57fa-ad03-6b2708b1d906', NULL, '493f827d-b631-53ec-8233-a85d1f020cb5', 'Im proud of you and I dont even know you. This is growth.', NOW() - INTERVAL '13 days', true),
('fee1f55e-15de-5a14-a988-4e73360fa618', NULL, 'f3c02198-e14a-5568-91ec-616b44b0a5de', 'Its not normal but its so common that it feels normal. Inherited anxiety is real. The good news is you can heal it.', NOW() - INTERVAL '13 days', true),
('46d6fee7-2ae0-5b80-b2ff-7cc73805e89a', NULL, '0ab47ba1-9ef8-5bb9-b7f2-4c7e44695d60', 'Same. Grew up being told sexuality was sinful then got told I was wrong for being gay. My nervous system learned that sex = shame. Working on that now.', NOW() - INTERVAL '13 days', true),
('12cb3615-9a9c-57f6-a59f-5f6b05323ec1', NULL, '0ab47ba1-9ef8-5bb9-b7f2-4c7e44695d60', 'Have you tried slowing down? Like actually pausing and noticing where the shame is in your body? My therapist calls it "befriending" the feeling instead of fighting it.', NOW() - INTERVAL '13 days', true),
('82af3999-d523-5e8d-bf9d-c0e93240ff48', NULL, '3e65224b-a2f9-5c72-9bcb-de94ec6934a5', 'Dating apps are designed to make you feel replaceable. Everyone is. You swipe past thousands of people and thousands swipe past you. Its not personal but it feels personal.', NOW() - INTERVAL '12 days', true),
('cc06f0cb-a213-584b-bd9d-aac19e41091a', NULL, '3e65224b-a2f9-5c72-9bcb-de94ec6934a5', 'I deleted mine after realizing I was checking it more than messaging actual people I cared about. Just feeding the dopamine machine.', NOW() - INTERVAL '12 days', true),
('52b2a056-c610-51a2-9ce0-d4350e2d6e4e', NULL, 'bc825afc-3441-558c-84be-db5b25636004', 'Most people are terrified on dates. Theyre probably wondering the same thing about you. What if you just... told the truth?', NOW() - INTERVAL '12 days', true),
('040eac3b-96c2-5148-bc6c-eee384704c45', NULL, 'bc825afc-3441-558c-84be-db5b25636004', 'I did this recently and it was terrifying but also refreshing. She appreciated the honesty even when it wasnt all polished and perfect.', NOW() - INTERVAL '12 days', true),
('34ab37c4-617e-5864-80d5-c69701e92129', NULL, '6f766808-87b5-56da-8a5d-0e725b8a04db', 'Vulnerability is definitely scary. But rejection of the real you is better than acceptance of a fake version. At least thats what I tell myself.', NOW() - INTERVAL '11 days', true),
('d9d64348-53c2-5c90-b110-08e7c6ae5a63', NULL, '7f94e4ec-b383-5a3f-99ca-e9f412e74430', 'Growth AF. Saying no means you value yourself. Thats not guilt, thats integrity.', NOW() - INTERVAL '11 days', true),
('27d3e9b3-4024-5ff5-8f01-e05f459f7ffc', NULL, '415a04e0-408c-5ac4-b4cc-7f9296ef5357', 'This is not pathetic at all. Humans need touch. Were not designed to be alone. The fact that you recognize you need it is actually healthy.', NOW() - INTERVAL '11 days', true),
('dc6a7ee9-9f21-5f62-a6c8-408fe848c944', NULL, '415a04e0-408c-5ac4-b4cc-7f9296ef5357', 'I started going to cuddle puddle events and it helped so much. Just non-sexual physical affection with other humans. Changed my life.', NOW() - INTERVAL '11 days', true),
('14266917-45ee-528c-87c5-d36e2043aa63', NULL, '5c03ed36-b993-52b0-b201-3b059cb723f1', 'I think you can ask friends. Like literally say "I need a hug" or "can we just sit close?" Most people will say yes if you ask directly.', NOW() - INTERVAL '10 days', true),
('b8427208-2f20-5846-bf3d-b6831697e934', NULL, '5c03ed36-b993-52b0-b201-3b059cb723f1', 'The weird thing is if youre not sexual with it, people usually feel it and respond. Its not weird if it comes from a genuine place.', NOW() - INTERVAL '10 days', true),
('ea565908-c258-5313-af85-e60c5392afa5', NULL, 'e680c3bf-9afa-5152-a611-f48da7c0733e', 'Could you try asking him what would make cuddling better for him? Maybe a lighter sheet or spooning instead of full body contact? Compromise?', NOW() - INTERVAL '10 days', true),
('599c8155-f7d4-5a22-b1c4-b094e7b33666', NULL, 'e680c3bf-9afa-5152-a611-f48da7c0733e', 'This is a real incompatibility though. If touch is your love language and he doesnt speak it, thats something to address.', NOW() - INTERVAL '10 days', true),
('b5e8ba7e-9907-507f-a907-eaf510e8c7e3', NULL, 'de28d666-fdb0-5850-a2ab-ad4acb64a1b9', 'Weight gain hit me the same way. The invisibility stung more than I expected. Still working on seeing myself with kindness.', NOW() - INTERVAL '9 days', true),
('a7bee3dd-a8bc-5aac-8e93-5c946b9ffb42', NULL, 'de28d666-fdb0-5850-a2ab-ad4acb64a1b9', 'Your brain isnt broken, its just trained. Media trained it. Culture trained it. But you can retrain it.', NOW() - INTERVAL '9 days', true),
('a14a754a-41ec-5c43-93ca-d8b85984e3da', NULL, '989d6ade-5623-512b-aafc-788eed393dad', 'Self-acceptance gets easier when you stop tying it to appearance. Like I had to separate "my body works" from "my body looks a certain way."', NOW() - INTERVAL '9 days', true),
('1c67de08-04b3-54e1-a63a-e7a50f9b8421', NULL, 'b13335ee-69d6-5f42-91ca-9b93051ab6c4', 'This shift is real. When I started moving for how it felt instead of how it looked, everything changed. Less pressure. More joy.', NOW() - INTERVAL '9 days', true),
('704fd07c-dd0d-5a2a-8f46-c02c7325dfe3', NULL, 'ff20135a-f7e2-5866-a8c8-82215443da49', 'Thats actually really healthy. Fighting is normal. Its how you fight and what happens after that matters.', NOW() - INTERVAL '8 days', true),
('42dc8ceb-c5ff-51b2-86ad-074881254e08', NULL, 'ff20135a-f7e2-5866-a8c8-82215443da49', 'I was terrified of conflict in my relationship. Realized I was taught that disagreement = the end. Learning thats not true.', NOW() - INTERVAL '8 days', true),
('6989938f-73c7-51fb-be92-0cc317177b80', NULL, '05d7328e-5b63-5e52-bbcb-6fb0d96ea181', 'Thats actually what makes a good partnership. He triggers you because he knows you. Thats intimacy.', NOW() - INTERVAL '8 days', true),
('73ac81b2-c4f8-52d5-8b61-7cb7f995c42a', NULL, '02507f50-b613-5269-a783-6393890702d1', 'Steady and comfortable sounds kind of perfect honestly. The beginning is intense but its exhausting. Safe is underrated.', NOW() - INTERVAL '8 days', true),
('0a7f518f-50a1-5b1e-bea1-f7ca7b8c0ac0', NULL, '02507f50-b613-5269-a783-6393890702d1', 'Real talk: most long relationships do lose novelty. Thats when you decide if the depth is enough. Sounds like maybe it is for you.', NOW() - INTERVAL '7 days', true),
('243784b6-e708-5a66-b996-200f8fdab7f6', NULL, '96743880-bfa9-5c7c-9752-9c4068361cbb', 'Relief is a real emotion and its valid. You can miss someone and still be glad theyre not in your life. Both are true.', NOW() - INTERVAL '7 days', true),
('402d188e-3f80-5f21-a8d0-08c87de0a8d6', NULL, '9926dcc3-9c55-5d51-bef6-71806482cea6', 'Religious trauma is so real. Its like a virus in your code that keeps running even after you intellectually leave the religion.', NOW() - INTERVAL '7 days', true),
('6e38b0a5-09fa-588b-9017-d3cfffeaf571', NULL, '9926dcc3-9c55-5d51-bef6-71806482cea6', 'Still in process of reconciling this. Some days I feel at peace with it, other days the shame is still there. Its slow work.', NOW() - INTERVAL '7 days', true),
('4d6b0a4a-7319-563d-b5d5-8fb873a9ed14', NULL, '0ee4e9e4-97d8-5087-ac2a-03214e69d0f0', 'That shift from shameful to sacred is one of the most powerful things Ive experienced. Rewires everything.', NOW() - INTERVAL '6 days', true),
('d4ce40d4-4198-5847-aedb-dcce397aa9fa', NULL, '0bb1cb5b-5c9c-5d02-ac03-b7704bbd0437', 'Never thought about it this way but yes. Presence and consent are absolutely spiritual practices.', NOW() - INTERVAL '6 days', true),
('ddf9441e-ac71-58f2-913f-e7dcb7ddf515', NULL, '643fc66e-d909-5a9b-b482-ebf21020ebd8', 'This question has consumed me lately. Starting to think real masculinity might be the opposite of what were taught.', NOW() - INTERVAL '6 days', true),
('e6188a75-5f30-548b-a17c-a64a20bac6de', NULL, '643fc66e-d909-5a9b-b482-ebf21020ebd8', 'Turns out I was trying to prove it to my father who wasnt even around to see it. Wild.', NOW() - INTERVAL '6 days', true),
('ca22d2b4-d4ec-5bee-ad9a-1250764fb8de', NULL, '8ea1f522-5ffd-5043-8200-f2be0fc8dbb4', 'The gym crying experience hits different when you realize nobody cares. Its actually liberating.', NOW() - INTERVAL '5 days', true),
('e24bdd62-f7c5-577d-abec-d6271f427418', NULL, 'ff72492f-5224-507c-a61d-d4ca3cf84522', 'Softness is the strongest thing Ive learned. Took me way too long.', NOW() - INTERVAL '5 days', true),
('5537282e-35a3-5938-ac35-f9929e6b6294', NULL, 'd663a5cf-4ecb-5ee7-88cc-188288b84af7', 'Have you looked into attachment theory? Understanding my avoidant style helped me stop judging myself for it.', NOW() - INTERVAL '5 days', true),
('cea9bfb0-2a27-5ea6-9d98-b7e1573ea6de', NULL, 'd663a5cf-4ecb-5ee7-88cc-188288b84af7', 'I do this too. Getting better at catching myself before I sabotage. Small wins.', NOW() - INTERVAL '5 days', true),
('a46cc790-bdb3-5a35-91b7-d662d5cd3134', NULL, 'b6d2d9e1-e6c6-5342-aa56-eb4e48390663', 'This. I watched my parents do the same thing and swore Id be different. Then realized I was exactly the same.', NOW() - INTERVAL '4 days', true),
('f16d17b9-8bb2-5ae4-b554-fe90b834b7dc', NULL, '697a75ed-d32a-5901-b1fe-d9f36d37c570', 'I do this constantly. Therapist says its hypervigilance. My nervous system is looking for danger that isnt there.', NOW() - INTERVAL '4 days', true),
('336c2045-c291-5e54-aafb-229c70e7ca57', NULL, '09bfd7d6-bd0b-5c24-98ca-e07d4c9d6027', 'Welcome. Were all terrified. Thats why were here. Youre in good company.', NOW() - INTERVAL '4 days', true),
('7adc2a2a-bb75-5e8b-8d59-e367b2b408e6', NULL, 'f42d0f22-bd50-51c9-b475-bc5c483bae05', 'Real talk: coming out solved nothing for me either. Just opened a door to work on the real stuff.', NOW() - INTERVAL '4 days', true),
('71d8d815-451f-53e2-a3f6-0cfd2b75c69a', NULL, 'f42d0f22-bd50-51c9-b475-bc5c483bae05', 'This is actually healing to hear. Thought I was broken for not feeling like everything changed.', NOW() - INTERVAL '3 days', true),
